#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int ans = (N * M + 1) / 2;
        printf("%d\n", ans);
    }
    return 0;
}

